const params = ($json.query && typeof $json.query === 'object') ? $json.query : {};
const q = (params.q || '').trim();
const type = (params.type || 'general').trim();

if (q.length < 2) {
  return [{ json: { valid: false, q, type, is_general: false, sql: null } }];
}

function esc(s) { return String(s).replace(/'/g, "''"); }
const safeQ = esc(q);

// Build prefix-aware tsquery: last word gets :* so partial words match while typing
// "merc" → to_tsquery('english', 'merc:*')  — matches mercury, merchant, etc.
// "star mer" → to_tsquery('english', 'star & mer:*')
const words = safeQ.trim().split(/\s+/).filter(function(w) { return w.length > 0; });
const tsqParts = words.map(function(w, i) {
  return (i === words.length - 1) ? w + ':*' : w;
});
const tsqStr = tsqParts.join(' & ');
const tsq = "to_tsquery('english', '" + tsqStr + "')";

const is_general = !type || type === 'general';

let sql;
if (is_general) {
  sql = "SELECT slug AS entity_slug, name AS entity_name, entity_type, manufacturer, payload->'rsi'->'images'->>'slideshow_pager' AS image_url, COUNT(*) OVER() AS total_count FROM entity_display WHERE search_vector @@ " + tsq + " AND hidden = false ORDER BY ts_rank(search_vector, " + tsq + ") DESC LIMIT 50";
} else {
  sql = "SELECT slug AS entity_slug, name AS entity_name, entity_type, manufacturer, payload->'rsi'->'images'->>'slideshow_pager' AS image_url FROM entity_display WHERE search_vector @@ " + tsq + " AND entity_type = '" + esc(type) + "' AND hidden = false ORDER BY ts_rank(search_vector, " + tsq + ") DESC LIMIT 100";
}

return [{ json: { valid: true, q, type, is_general, sql } }];

const items = $input.all();
const buildSqlOut = $('Build SQL').first().json;
const is_general = buildSqlOut.is_general;

const validRows = items.filter(function(item) { return !!item.json.entity_slug; });

const results = validRows.map(function(item, idx) {
  const row = {
    entity_slug: item.json.entity_slug,
    entity_name: item.json.entity_name,
    entity_type: item.json.entity_type
  };
  if (item.json.manufacturer) { row.manufacturer = item.json.manufacturer; }
  row.image_url = item.json.image_url || null;
  row.kb_url = 'https://arkoncore.cc/kb/' + item.json.entity_type + '/' + item.json.entity_slug;
  row.api_url = 'https://arkoncore.cc/api/lookup?slug=' + item.json.entity_slug;
  if (is_general && idx === 0 && item.json.total_count !== undefined) {
    row.count = String(item.json.total_count);
  }
  return row;
});

return [{ json: { results: results } }];
